sys_atf_test_step.step:
(function step(assert, $library) {
    // Test Role Capability Map CRUD operations
    // Create
    var gr = new GlideRecord('u_role_capability_map');
    gr.initialize();
    gr.u_role = 'x_146833_idpkiroq.user';
    gr.u_capability = 'AI Orchestration';
    var id = gr.insert();
    assert.isTrue(id, 'Role capability map should be created');

    // Read
    gr = new GlideRecord('u_role_capability_map');
    gr.get(id);
    assert.isTrue(gr.isValid(), 'Role capability map should exist');

    // Update
    gr.u_role = 'x_146833_idpkiroq.admin';
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_role_capability_map');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'Role capability map should be deleted');
})(step, $library);
